class Solution {
public:
    int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    int minStable(vector<int>& nums, int maxC) {
        int n = nums.size();
        int res = 0;
        int left = 0;
        int changes = 0;

        for (int right = 0; right < n; right++) {
            if (nums[right] < 2) changes++;
            while (changes > maxC) {
                if (nums[left] < 2) changes--;
                left++;
            }
            if (right - left + 1 > res) {
                int g = nums[left];
                for (int i = left + 1; i <= right; i++) {
                    g = gcd(g, nums[i]);
                }
                if (g >= 2) res = right - left + 1;
            }
        }
        return res == 0 ? 0 : res;
    }
};
